/// Shared Packed Parse Forest (SPPF) implementation


/// Base class for all forest nodes
sealed class ForestNode {
  final PatternSymbol symbol;
  final int start;
  final int end;

  ForestNode(this.start, this.end, this.symbol);

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is ForestNode &&
          runtimeType == other.runtimeType &&
          start == other.start &&
          end == other.end &&
          symbol == other.symbol;

  @override
  int get hashCode => start.hashCode ^ end.hashCode ^ symbol.hashCode;
}

/// Terminal node (matches a token)
class TerminalNode extends ForestNode {
  final int token;

  TerminalNode(super.start, super.end, super.pattern, this.token);

  @override
  bool operator ==(Object other) =>
      identical(this, other) || super == other && other is TerminalNode && token == (other).token;

  @override
  int get hashCode => super.hashCode ^ token.hashCode;

  @override
  String toString() => 'Terminal($token, [$start, $end))';
}

/// Marker node (for named positions / @mark identifiers)
class MarkerNode extends ForestNode {
  final String name;

  MarkerNode(int position, PatternSymbol symbol, this.name) : super(position, position, symbol);

  @override
  bool operator ==(Object other) =>
      identical(this, other) || super == other && other is MarkerNode && name == (other).name;

  @override
  int get hashCode => super.hashCode ^ name.hashCode;

  @override
  String toString() => 'Marker(\$name)[$start]';
}

/// Symbolic node (non-terminal)
class SymbolicNode extends ForestNode {
  final Set<Family> families;

  SymbolicNode(super.start, super.end, super.symbol) : families = {};

  void addFamily(Family family) {
    if (!families.contains(family)) {
      families.add(family);
    }
  }

  @override
  bool operator ==(Object other) =>
      identical(this, other) || super == other && other is SymbolicNode && symbol == other.symbol;

  @override
  int get hashCode => super.hashCode ^ symbol.hashCode;

  @override
  String toString() => '$symbol[$start:$end]';
}

/// Intermediate node (represents semantic actions on children)
class IntermediateNode extends ForestNode {
  final Set<Family> families;

  IntermediateNode(super.start, super.end, super.symbol) : families = {};

  void addFamily(Family family) {
    if (!families.contains(family)) {
      families.add(family);
    }
  }

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      super == other &&
          other is IntermediateNode &&
          families.difference(other.families).isEmpty &&
          families.length == other.families.length;

  @override
  int get hashCode => super.hashCode;

  @override
  String toString() => 'Intermediate($symbol, [$start, $end))';
}

/// Family of parse derivations (alternatives)
sealed class Family {
  final List<Mark> marks;
  const Family([this.marks = const []]);
  const factory Family.epsilon([List<Mark> marks]) = _EpsilonFamily;
  const factory Family.unary(ForestNode child, [List<Mark> marks]) = _UnaryFamily;
  const factory Family.binary(ForestNode left, ForestNode right, [List<Mark> marks]) =
      _BinaryFamily;

  Iterable<ForestNode> get children sync* {
    switch (this) {
      case _EpsilonFamily _:
        break;
      case _UnaryFamily self:
        yield self.child;
      case _BinaryFamily self:
        yield self.left;
        yield self.right;
    }
  }
}

class _EpsilonFamily extends Family {
  const _EpsilonFamily([super.marks]);

  @override
  bool operator ==(Object other) => identical(this, other) || other is _EpsilonFamily;

  @override
  int get hashCode => marks.hashCode;
}

/// Single child — terminal, or a rule wrapping one sub-pattern
class _UnaryFamily extends Family {
  final ForestNode child;
  const _UnaryFamily(this.child, [super.marks]);

  @override
  bool operator ==(Object other) =>
      identical(this, other) || other is _UnaryFamily && child == other.child;

  @override
  int get hashCode => child.hashCode;
}

/// Binary Seq(left, right) — the normal case
class _BinaryFamily extends Family {
  final ForestNode left;
  final ForestNode right;
  const _BinaryFamily(this.left, this.right, [super.marks]);

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is _BinaryFamily && left == other.left && right == other.right;

  @override
  int get hashCode => left.hashCode ^ right.hashCode;
}

/// Epsilon node (empty parse)
class EpsilonNode extends ForestNode {
  EpsilonNode(int position, PatternSymbol symbol) : super(position, position, symbol);

  @override
  String toString() => 'ε[$start]';
}

/// Forest node manager (deduplicates and caches nodes)
class ForestNodeManager {
  final Map<String, ForestNode> _nodeCache = {};
  final Set<SymbolicNode> _symbolicNodes = {};
  final Set<TerminalNode> _terminalNodes = {};
  final Set<IntermediateNode> _intermediateNodes = {};
  final Set<MarkerNode> _markerNodes = {};

  String _makeCacheKey(String type, int start, int end, PatternSymbol symbol) {
    return '$type:$start:$end:$symbol';
  }

  /// Get or create a terminal node
  TerminalNode terminal(int start, int end, PatternSymbol symbol, int token) {
    final key = _makeCacheKey('term', start, end, symbol);
    if (_nodeCache[key] case TerminalNode node) {
      return node;
    }
    final node = TerminalNode(start, end, symbol, token);
    _nodeCache[key] = node;
    _terminalNodes.add(node);
    return node;
  }

  /// Get or create a symbolic node
  SymbolicNode symbolic(int start, int end, PatternSymbol symbol) {
    final key = _makeCacheKey('sym', start, end, symbol);
    if (_nodeCache[key] case SymbolicNode node) {
      return node;
    }
    final node = SymbolicNode(start, end, symbol);
    _nodeCache[key] = node;
    _symbolicNodes.add(node);
    return node;
  }

  /// Get or create an intermediate node
  IntermediateNode intermediate(int start, int end, PatternSymbol symbol) {
    final key = _makeCacheKey('inter', start, end, symbol);
    if (_nodeCache[key] case IntermediateNode node) {
      return node;
    }
    final node = IntermediateNode(start, end, symbol);
    _nodeCache[key] = node;
    _intermediateNodes.add(node);
    return node;
  }

  /// Get or create an epsilon node
  EpsilonNode epsilon(int position, PatternSymbol symbol) {
    final key = _makeCacheKey('eps', position, position, symbol);
    if (_nodeCache[key] case EpsilonNode node) {
      return node;
    }
    final node = EpsilonNode(position, symbol);
    _nodeCache[key] = node;
    return node;
  }

  /// Get or create a marker node
  MarkerNode marker(int position, Marker marker) {
    final key = _makeCacheKey('mark', position, position, marker.symbolId!);
    if (_nodeCache[key] case MarkerNode node) {
      return node;
    }
    final node = MarkerNode(position, marker.symbolId!, marker.name);
    _nodeCache[key] = node;
    _markerNodes.add(node);
    return node;
  }

  Set<SymbolicNode> get symbolicNodes => _symbolicNodes;
  Set<TerminalNode> get terminalNodes => _terminalNodes;
  Set<IntermediateNode> get intermediateNodes => _intermediateNodes;
  Set<MarkerNode> get markerNodes => _markerNodes;
}

/// Parse forest representation
class ParseForest {
  final ForestNodeManager nodeManager;
  final SymbolicNode root;
  final List<Mark> marks;

  ParseForest(this.nodeManager, this.root, this.marks);

  /// Count total nodes in the forest
  int countNodes() {
    final visited = <ForestNode>{};
    _countNodesRecursive(root, visited);
    return visited.length;
  }

  void _countNodesRecursive(ForestNode node, Set<ForestNode> visited) {
    if (visited.contains(node)) return;
    visited.add(node);

    if (node is SymbolicNode) {
      for (final family in node.families) {
        for (final child in family.children) {
          _countNodesRecursive(child, visited);
        }
      }
    } else if (node is IntermediateNode) {
      for (final family in node.families) {
        for (final child in family.children) {
          _countNodesRecursive(child, visited);
        }
      }
    }
  }

  /// Count total families (derivations) in the forest
  int countFamilies() {
    final visited = <ForestNode>{};
    return _countFamiliesRecursive(root, visited);
  }

  int _countFamiliesRecursive(ForestNode node, Set<ForestNode> visited) {
    if (visited.contains(node)) return 0;
    visited.add(node);

    int count = 0;
    if (node case SymbolicNode(:var families) || IntermediateNode(:var families)) {
      count = families.length;
      for (final family in families) {
        for (final child in family.children) {
          count += _countFamiliesRecursive(child, visited);
        }
      }
    }
    return count;
  }

  /// Count derivations using SCC (Strongly Connected Components) analysis.
  /// This is more efficient than enumeration for large forests by:
  /// 1. Identifying shared structure and cycles
  /// 2. Computing derivation counts via dynamic programming
  /// 3. Detecting potentially infinite derivations
  ///
  /// Returns a map with:
  /// - 'count': total number of derivations
  /// - 'hasCycles': whether the forest has cycles (left-recursion)
  /// - 'sccs': number of strongly connected components
  Map<String, Object?> countDerivationsWithSCC() {
    final sccs = _findSCCs();
    final sccMap = <ForestNode, int>{};

    // Map each node to its SCC id
    for (int i = 0; i < sccs.length; i++) {
      for (final node in sccs[i]) {
        sccMap[node] = i;
      }
    }

    // Check for cycles: if any SCC has more than one node, or if a node reaches itself
    bool hasCycles = sccs.any((scc) => scc.length > 1);

    // Count derivations using memoization
    final memo = <ForestNode, BigInt>{};
    final inProgress = <ForestNode>{};

    final count = _countDerivationsDP(root, memo, inProgress, sccMap);

    return {
      'count': count,
      'hasCycles': hasCycles,
      'sccs': sccs.length,
      'forestSize': countNodes(),
    };
  }

  /// Find strongly connected components using Tarjan's algorithm
  List<Set<ForestNode>> _findSCCs() {
    int index = 0;
    final stack = <ForestNode>[];
    final indices = <ForestNode, int>{};
    final lowlinks = <ForestNode, int>{};
    final onStack = <ForestNode, bool>{};
    final sccs = <Set<ForestNode>>[];

    void strongConnect(ForestNode node) {
      indices[node] = index;
      lowlinks[node] = index;
      index++;
      stack.add(node);
      onStack[node] = true;

      // Collect all successors (children) of this node
      final successors = _getSuccessors(node);

      for (final successor in successors) {
        if (!indices.containsKey(successor)) {
          strongConnect(successor);
          lowlinks[node] = (lowlinks[node]! < lowlinks[successor]!)
              ? lowlinks[node]!
              : lowlinks[successor]!;
        } else if (onStack[successor] == true) {
          lowlinks[node] = (lowlinks[node]! < indices[successor]!)
              ? lowlinks[node]!
              : indices[successor]!;
        }
      }

      if (lowlinks[node] == indices[node]) {
        final scc = <ForestNode>{};
        late ForestNode successor;
        do {
          successor = stack.removeLast();
          onStack[successor] = false;
          scc.add(successor);
        } while (successor != node);
        sccs.add(scc);
      }
    }

    // Run Tarjan's algorithm on all nodes
    final allNodes = <ForestNode>{};
    _collectAllNodes(root, allNodes);

    for (final node in allNodes) {
      if (!indices.containsKey(node)) {
        strongConnect(node);
      }
    }

    return sccs;
  }

  /// Get all successor nodes (children) in the forest
  Set<ForestNode> _getSuccessors(ForestNode node) {
    final successors = <ForestNode>{};

    if (node is SymbolicNode) {
      for (final family in node.families) {
        successors.addAll(family.children);
      }
    } else if (node is IntermediateNode) {
      for (final family in node.families) {
        successors.addAll(family.children);
      }
    }

    return successors;
  }

  /// Collect all nodes reachable from the root
  void _collectAllNodes(ForestNode node, Set<ForestNode> collected) {
    if (collected.contains(node)) return;
    collected.add(node);

    if (node is SymbolicNode) {
      for (final family in node.families) {
        for (final child in family.children) {
          _collectAllNodes(child, collected);
        }
      }
    } else if (node is IntermediateNode) {
      for (final family in node.families) {
        for (final child in family.children) {
          _collectAllNodes(child, collected);
        }
      }
    }
  }

  /// Dynamic programming to count derivations with cycle detection
  BigInt _countDerivationsDP(
    ForestNode node,
    Map<ForestNode, BigInt> memo,
    Set<ForestNode> inProgress,
    Map<ForestNode, int> sccMap,
  ) {
    if (memo.containsKey(node)) {
      return memo[node]!;
    }

    // Detect cycle: if node is in progress, we have a cycle
    if (inProgress.contains(node)) {
      // In a well-formed parse forest, this shouldn't happen with bounded input
      // But if it does, return 1 to avoid infinite loops (actual count is undefined)
      return BigInt.one;
    }

    inProgress.add(node);

    BigInt count = BigInt.zero;

    if (node is SymbolicNode) {
      if (node.families.isEmpty) {
        count = BigInt.one; // Base case: leaf node
      } else {
        for (final family in node.families) {
          // Count = product of child counts
          BigInt familyCount = BigInt.one;
          for (final child in family.children) {
            final childCount = _countDerivationsDP(child, memo, inProgress, sccMap);
            familyCount *= childCount;
          }
          count += familyCount;
        }
      }
    } else if (node is IntermediateNode) {
      if (node.families.isEmpty) {
        count = BigInt.one;
      } else {
        for (final family in node.families) {
          BigInt familyCount = BigInt.one;
          for (final child in family.children) {
            final childCount = _countDerivationsDP(child, memo, inProgress, sccMap);
            familyCount *= childCount;
          }
          count += familyCount;
        }
      }
    } else {
      // Terminal, epsilon, or marker: count as 1
      count = BigInt.one;
    }

    inProgress.remove(node);
    memo[node] = count;
    return count;
  }

  /// Lazily yields all parse trees contained in the forest.
  Iterable<ParseTree> extract() sync* {
    yield* _extractTrees(root);
  }

  Iterable<ParseTree> _extractTrees(ForestNode node) sync* {
    if (node is SymbolicNode) {
      if (node.families.isEmpty) {
        yield ParseTree(node, const []);
        return;
      }
      for (final family in node.families) {
        if (family.children.isEmpty) {
          yield ParseTree(node, const []);
        } else {
          yield* _extractFamilyTrees(node, family);
        }
      }
    } else if (node is IntermediateNode) {
      if (node.families.isEmpty) {
        yield ParseTree(node, const []);
        return;
      }
      for (final family in node.families) {
        if (family.children.isEmpty) {
          yield ParseTree(node, const []);
        } else {
          yield* _extractFamilyTrees(node, family);
        }
      }
    } else {
      yield ParseTree(node, const []);
    }
  }

  /// Lazily yields one [ParseTree] per combination of child subtrees for [family].
  Iterable<ParseTree> _extractFamilyTrees(ForestNode parent, Family family) sync* {
    switch (family) {
      case _EpsilonFamily():
        break;
      case _UnaryFamily(:final child):
        for (final tree in _extractTrees(child)) {
          yield ParseTree(parent, [tree]);
        }
      case _BinaryFamily(:final left, :final right):
        for (final l in _extractTrees(left)) {
          for (final r in _extractTrees(right)) {
            yield ParseTree(parent, [l, r]);
          }
        }
    }
  }

  @override
  String toString() {
    return 'ParseForest(root=$root, nodes=${countNodes()}, families=${countFamilies()})';
  }
}

/// A single parse tree extracted from the forest
class ParseTree {
  final ForestNode node;
  final List<ParseTree> children;

  ParseTree(this.node, this.children);

  /// Convert to a readable string representation
  String toTreeString([int indent = 0]) {
    final prefix = '  ' * indent;
    final str = '$prefix$node\n';
    return str + children.map((c) => c.toTreeString(indent + 1)).join('');
  }

  String toPrecedenceString(String input) {
    if (children.isEmpty) {
      return input.substring(node.start, node.end);
    }

    List<String> mapped = children
        .where((c) => c.node.start != c.node.end)
        .map((c) => c.toPrecedenceString(input))
        .toList();

    if (mapped.length == 1) {
      return mapped.single;
    }

    return "(${mapped.join("")})";
  }

  @override
  String toString() => node.toString();
}

// --- $filename ---
/// Binary Subtree Representation (BSR) for compact derivation recording.
///
/// A BSR set is populated *during* parsing. Each entry records that a rule
/// was successfully completed over a specific input span.  The SPPF can then
/// be derived on-demand from these entries rather than from an exhaustive
/// grammar walk.
///
/// Reference: Scott & Johnstone, "GLL Parse-Tree Generation" (2013).


/// A BSR entry (RuleSlot, start, pivot, end) according to Scott & Johnstone.
typedef BsrEntry = (PatternSymbol slot, int start, int pivot, int end);

extension BsrEntryMethods on BsrEntry {
  PatternSymbol get slot => $1;
  int get start => $2;
  int get pivot => $3;
  int get end => $4;
}

extension type const BsrPattern(String thing) {}

/// The set of all [BsrEntry] instances accumulated during a parse.
class BsrSet {
  final Map<(PatternSymbol, int start, int end), Set<int>> _pivots = {};

  /// Add a rule-completion entry.
  void add(PatternSymbol patternSymbol, int start, int pivot, int end) {
    _pivots.putIfAbsent((patternSymbol, start, end), Set.new).add((pivot));
  }

  /// Total number of recorded rule-completion entries.
  int get length => _pivots.values.expand((v) => v).length;
  Iterable<BsrEntry> get entries =>
      _pivots.entries.expand((e) => e.value.map((v) => (e.key.$1, e.key.$2, e.key.$3, v)));

  Set<int> pivotsFor(PatternSymbol ruleSymbol, int start, int end) {
    return _pivots.putIfAbsent((ruleSymbol, start, end), Set.new).toSet();
  }

  /// Build an SPPF rooted at [startRule] over the full input.
  SymbolicNode? buildSppf(
    GrammarInterface grammar,
    Rule startRule,
    String input,
    ForestNodeManager nodeManager,
  ) {
    final memo = <String, SymbolicNode?>{};
    final inProgress = <String, bool>{};

    return SppfBuilder(
          this,
          nodeManager,
          input,
          grammar.symbolRegistry,
          grammar.childrenRegistry,
        ) //
        .buildNode(startRule.symbolId!, 0, input.length, memo, inProgress);
  }

  @override
  String toString() => 'BsrSet(${_pivots.length} entries)';
}

sealed class BsrParseOutcome {}

final class BsrParseError implements BsrParseOutcome, Exception {
  final int position;
  const BsrParseError(this.position);
}

final class BsrParseSuccess implements BsrParseOutcome {
  final BsrSet bsrSet;
  final List<Mark> marks;
  const BsrParseSuccess(this.bsrSet, this.marks);
}

sealed class _Task {
  const _Task();
}

// --- Core Execution Tasks ---
class _DoBuildNode extends _Task {
  final String key;
  final PatternSymbol ruleSymbol;
  final int start, end;
  final int? minPrecedenceLevel;
  final bool isRoot;

  const _DoBuildNode(
    this.key,
    this.ruleSymbol,
    this.start,
    this.end,
    this.minPrecedenceLevel, {
    this.isRoot = false,
  });
}

class _EvalPattern extends _Task {
  final PatternSymbol currentRule;
  final Pattern pattern;
  final int start, end, ruleStart;
  final int? minPrecedenceLevel;

  const _EvalPattern(
    this.currentRule,
    this.pattern,
    this.start,
    this.end,
    this.ruleStart,
    this.minPrecedenceLevel,
  );
}

// --- Continuation Tasks (Replacing callbacks) ---
class _ContBuildNodeFinish extends _Task {
  final SymbolicNode symNode;
  final String key;
  const _ContBuildNodeFinish(this.symNode, this.key);
}

class _ContAltCombine extends _Task {
  const _ContAltCombine();
}

class _ContRuleCallFinish extends _Task {
  const _ContRuleCallFinish();
}

class _ContActionFinish extends _Task {
  final int start, end;
  final PatternSymbol symbolId;
  const _ContActionFinish(this.start, this.end, this.symbolId);
}

// --- Loop State Tasks ---
class _ContSeqLoop extends _Task {
  final PatternSymbol currentRule;
  final Seq pattern;
  final int start, end, ruleStart;
  final int? minPrecedenceLevel;
  final Iterator<int> it;
  IntermediateNode? seqNode;

  _ContSeqLoop(
    this.currentRule,
    this.pattern,
    this.start,
    this.end,
    this.ruleStart,
    this.minPrecedenceLevel,
    this.it,
  );
}

class _ContSeqLeft extends _Task {
  final _ContSeqLoop loopTask;
  final int mid;
  _ContSeqLeft(this.loopTask, this.mid);
}

class _ContSeqRight extends _Task {
  final _ContSeqLoop loopTask;
  final List<ForestNode> leftNodes;
  _ContSeqRight(this.loopTask, this.leftNodes);
}

class _ContPlusLoop extends _Task {
  final PatternSymbol currentRule;
  final Plus pattern;
  final int start, end, ruleStart;
  final int? minPrecedenceLevel;
  final Iterator<int> it;
  IntermediateNode? plusNode;

  _ContPlusLoop(
    this.currentRule,
    this.pattern,
    this.start,
    this.end,
    this.ruleStart,
    this.minPrecedenceLevel,
    this.it,
  );
}

class _ContPlusLeft extends _Task {
  final _ContPlusLoop loopTask;
  final int mid;
  _ContPlusLeft(this.loopTask, this.mid);
}

class _ContPlusRight extends _Task {
  final _ContPlusLoop loopTask;
  final List<ForestNode> headNodes;
  _ContPlusRight(this.loopTask, this.headNodes);
}

class _ContPlusFinal extends _Task {
  final _ContPlusLoop loopTask;
  _ContPlusFinal(this.loopTask);
}

class _ContStarLoop extends _Task {
  final PatternSymbol currentRule;
  final Star pattern;
  final int start, end, ruleStart;
  final int? minPrecedenceLevel;
  final Iterator<int> it;
  IntermediateNode? starNode;

  _ContStarLoop(
    this.currentRule,
    this.pattern,
    this.start,
    this.end,
    this.ruleStart,
    this.minPrecedenceLevel,
    this.it,
  );
}

class _ContStarLeft extends _Task {
  final _ContStarLoop loopTask;
  final int mid;
  const _ContStarLeft(this.loopTask, this.mid);
}

class _ContStarRight extends _Task {
  final _ContStarLoop loopTask;
  final List<ForestNode> headNodes;
  const _ContStarRight(this.loopTask, this.headNodes);
}

class _ContConjLeft extends _Task {
  final PatternSymbol currentRule;
  final Conj pattern;
  final int start, end, ruleStart;
  final int? minPrecedenceLevel;

  const _ContConjLeft(
    this.currentRule,
    this.pattern,
    this.start,
    this.end,
    this.ruleStart,
    this.minPrecedenceLevel,
  );
}

class _ContConjRight extends _Task {
  final _ContConjLeft startTask;
  final List<ForestNode> leftNodes;

  const _ContConjRight(this.startTask, this.leftNodes);
}

class SppfBuilder {
  final BsrSet bsr;
  final ForestNodeManager nodeManager;
  final String input;

  final Map<PatternSymbol, Pattern> patternRegistry;
  final Map<PatternSymbol, List<PatternSymbol>> childrenRegistry;

  const SppfBuilder(
    this.bsr,
    this.nodeManager,
    this.input,
    this.patternRegistry,
    this.childrenRegistry,
  );

  List<PatternSymbol> getChildrenOf(PatternSymbol symbol) {
    if (childrenRegistry[symbol] case List<PatternSymbol> children) {
      return children;
    }
    throw StateError("Couldn't find the children of $symbol.");
  }

  Pattern getPatternOf(PatternSymbol symbol) {
    if (patternRegistry[symbol] case Pattern pattern) {
      return pattern;
    }
    throw StateError("Couldn't find the pattern of $symbol.");
  }

  // Unified public API - returns synchronously
  SymbolicNode? buildNode(
    PatternSymbol ruleSymbol,
    int start,
    int end,
    Map<String, SymbolicNode?> memo,
    Map<String, bool> inProgress, {
    int? minPrecedenceLevel,
  }) {
    final key = '$ruleSymbol:$start:$end';

    // The Two-Stack VM
    final taskStack = <_Task>[
      _DoBuildNode(key, ruleSymbol, start, end, minPrecedenceLevel, isRoot: true),
    ];
    final valueStack = <Object?>[]; // Holds List<ForestNode> and SymbolicNode?

    while (taskStack.isNotEmpty) {
      final task = taskStack.removeLast();

      if (task is _DoBuildNode) {
        if (memo.containsKey(task.key)) {
          valueStack.add(memo[task.key]);
          continue;
        }
        if (inProgress[task.key] == true) {
          valueStack.add(null);
          continue;
        }

        inProgress[task.key] = true;
        final symNode = nodeManager.symbolic(task.start, task.end, task.ruleSymbol);

        // 2. Schedule the completion logic for AFTER the pattern evaluates
        taskStack.add(_ContBuildNodeFinish(symNode, task.key));

        // 1. Evaluate the pattern
        final patternToEval = getPatternOf(getChildrenOf(task.ruleSymbol).single);

        taskStack.add(
          _EvalPattern(
            task.ruleSymbol,
            patternToEval,
            task.start,
            task.end,
            task.start,
            task.minPrecedenceLevel,
          ),
        );
      } else if (task is _ContBuildNodeFinish) {
        final childNodes = valueStack.removeLast() as List<ForestNode>;
        for (final child in childNodes) {
          task.symNode.addFamily(Family.unary(child));
        }

        inProgress[task.key] = false;
        final result = task.symNode.families.isNotEmpty ? task.symNode : null;
        memo[task.key] = result;
        valueStack.add(result);
      } else if (task is _EvalPattern) {
        _executePatternTask(task, taskStack, valueStack);
      }
      // --- Structural Continuations ---
      else if (task is _ContAltCombine) {
        final rightRes = valueStack.removeLast() as List<ForestNode>;
        final leftRes = valueStack.removeLast() as List<ForestNode>;
        valueStack.add([...leftRes, ...rightRes]);
      } else if (task is _ContRuleCallFinish) {
        final node = valueStack.removeLast() as SymbolicNode?;
        valueStack.add(node != null ? [node] : <ForestNode>[]);
      } else if (task is _ContActionFinish) {
        final nodes = valueStack.removeLast() as List<ForestNode>;
        if (nodes.isEmpty) {
          valueStack.add(<ForestNode>[]);
        } else {
          final node = nodeManager.intermediate(task.start, task.end, task.symbolId);
          for (final n in nodes) node.addFamily(Family.unary(n));
          valueStack.add([node]);
        }
      }
      // --- Conj ---
      else if (task is _ContConjLeft) {
        final leftNodes = valueStack.removeLast() as List<ForestNode>;
        if (leftNodes.isEmpty) {
          valueStack.add(<ForestNode>[]); // Short circuit
        } else {
          taskStack.add(_ContConjRight(task, leftNodes));
          taskStack.add(
            _EvalPattern(
              task.currentRule,
              task.pattern.right,
              task.start,
              task.end,
              task.ruleStart,
              task.minPrecedenceLevel,
            ),
          );
        }
      } else if (task is _ContConjRight) {
        final rightNodes = valueStack.removeLast() as List<ForestNode>;
        if (rightNodes.isEmpty) {
          valueStack.add(<ForestNode>[]);
        } else {
          final node = nodeManager.intermediate(
            task.startTask.start,
            task.startTask.end,
            task.startTask.pattern.symbolId!,
          );
          for (final l in task.leftNodes) {
            for (final r in rightNodes) node.addFamily(Family.binary(l, r));
          }
          valueStack.add([node]);
        }
      }
      // --- Seq Loop ---
      else if (task is _ContSeqLoop) {
        if (!task.it.moveNext()) {
          valueStack.add(task.seqNode != null ? [task.seqNode!] : <ForestNode>[]);
        } else {
          final mid = task.it.current;
          taskStack.add(task); // Re-queue loop state
          taskStack.add(_ContSeqLeft(task, mid));
          taskStack.add(
            _EvalPattern(
              task.currentRule,
              task.pattern.left,
              task.start,
              mid,
              task.ruleStart,
              task.minPrecedenceLevel,
            ),
          );
        }
      } else if (task is _ContSeqLeft) {
        final leftNodes = valueStack.removeLast() as List<ForestNode>;
        if (leftNodes.isEmpty) {
          // Skip right evaluation, let loop continue on next tick
        } else {
          taskStack.add(_ContSeqRight(task.loopTask, leftNodes));
          taskStack.add(
            _EvalPattern(
              task.loopTask.currentRule,
              task.loopTask.pattern.right,
              task.mid,
              task.loopTask.end,
              task.loopTask.ruleStart,
              task.loopTask.minPrecedenceLevel,
            ),
          );
        }
      } else if (task is _ContSeqRight) {
        final rightNodes = valueStack.removeLast() as List<ForestNode>;
        if (rightNodes.isNotEmpty) {
          task.loopTask.seqNode ??= nodeManager.intermediate(
            task.loopTask.start,
            task.loopTask.end,
            task.loopTask.pattern.symbolId!,
          );
          for (final l in task.leftNodes) {
            for (final r in rightNodes) task.loopTask.seqNode!.addFamily(Family.binary(l, r));
          }
        }
      }
      // --- Plus Loop ---
      else if (task is _ContPlusLoop) {
        if (!task.it.moveNext()) {
          taskStack.add(_ContPlusFinal(task));
          taskStack.add(
            _EvalPattern(
              task.currentRule,
              task.pattern.child,
              task.start,
              task.end,
              task.ruleStart,
              task.minPrecedenceLevel,
            ),
          );
        } else {
          final mid = task.it.current;
          taskStack.add(task); // Re-queue loop state
          taskStack.add(_ContPlusLeft(task, mid));
          taskStack.add(
            _EvalPattern(
              task.currentRule,
              task.pattern.child,
              task.start,
              mid,
              task.ruleStart,
              task.minPrecedenceLevel,
            ),
          );
        }
      } else if (task is _ContPlusLeft) {
        final headNodes = valueStack.removeLast() as List<ForestNode>;
        if (headNodes.isNotEmpty) {
          taskStack.add(_ContPlusRight(task.loopTask, headNodes));
          taskStack.add(
            _EvalPattern(
              task.loopTask.currentRule,
              task.loopTask.pattern,
              task.mid,
              task.loopTask.end,
              task.loopTask.ruleStart,
              task.loopTask.minPrecedenceLevel,
            ),
          );
        }
      } else if (task is _ContPlusRight) {
        final tailNodes = valueStack.removeLast() as List<ForestNode>;
        if (tailNodes.isNotEmpty) {
          task.loopTask.plusNode ??= nodeManager.intermediate(
            task.loopTask.start,
            task.loopTask.end,
            task.loopTask.pattern.symbolId!,
          );
          for (final h in task.headNodes) {
            for (final t in tailNodes) task.loopTask.plusNode!.addFamily(Family.binary(h, t));
          }
        }
      } else if (task is _ContPlusFinal) {
        final nodes = valueStack.removeLast() as List<ForestNode>;
        if (nodes.isNotEmpty) {
          task.loopTask.plusNode ??= nodeManager.intermediate(
            task.loopTask.start,
            task.loopTask.end,
            task.loopTask.pattern.symbolId!,
          );
          for (final n in nodes) task.loopTask.plusNode!.addFamily(Family.unary(n));
        }
        valueStack.add(task.loopTask.plusNode != null ? [task.loopTask.plusNode!] : <ForestNode>[]);
      }
      // --- Star Loop ---
      else if (task is _ContStarLoop) {
        if (!task.it.moveNext()) {
          if (task.start == task.end) {
            task.starNode ??= nodeManager.intermediate(
              task.start,
              task.end,
              task.pattern.symbolId!,
            );
            task.starNode!.addFamily(
              Family.unary(nodeManager.epsilon(task.start, task.pattern.symbolId!)),
            );
          }
          valueStack.add(task.starNode != null ? [task.starNode!] : <ForestNode>[]);
        } else {
          final mid = task.it.current;
          taskStack.add(task); // Re-queue loop state
          taskStack.add(_ContStarLeft(task, mid));
          taskStack.add(
            _EvalPattern(
              task.currentRule,
              task.pattern.child,
              task.start,
              mid,
              task.ruleStart,
              task.minPrecedenceLevel,
            ),
          );
        }
      } else if (task is _ContStarLeft) {
        final headNodes = valueStack.removeLast() as List<ForestNode>;
        if (headNodes.isNotEmpty) {
          taskStack.add(_ContStarRight(task.loopTask, headNodes));
          taskStack.add(
            _EvalPattern(
              task.loopTask.currentRule,
              task.loopTask.pattern,
              task.mid,
              task.loopTask.end,
              task.loopTask.ruleStart,
              task.loopTask.minPrecedenceLevel,
            ),
          );
        }
      } else if (task is _ContStarRight) {
        final tailNodes = valueStack.removeLast() as List<ForestNode>;
        if (tailNodes.isNotEmpty) {
          task.loopTask.starNode ??= nodeManager.intermediate(
            task.loopTask.start,
            task.loopTask.end,
            task.loopTask.pattern.symbolId!,
          );
          for (final h in task.headNodes) {
            for (final t in tailNodes) task.loopTask.starNode!.addFamily(Family.binary(h, t));
          }
        }
      }
    }

    return valueStack.removeLast() as SymbolicNode?;
  }

  void _executePatternTask(_EvalPattern task, List<_Task> taskStack, List<dynamic> valueStack) {
    final pattern = task.pattern;
    final start = task.start;
    final end = task.end;

    switch (pattern) {
      case Token():
        if (start + 1 == end && pattern.match(input.codeUnitAt(start))) {
          valueStack.add([
            nodeManager.terminal(start, end, pattern.symbolId!, input.codeUnitAt(start)),
          ]);
        } else {
          valueStack.add(<ForestNode>[]);
        }
      case Marker():
        valueStack.add(start == end ? [nodeManager.marker(start, pattern)] : <ForestNode>[]);
      case Eps():
      case And():
      case Not():
        valueStack.add(
          start == end ? [nodeManager.epsilon(start, pattern.symbolId!)] : <ForestNode>[],
        );

      case Alt():
        // LIFO: Right goes on first, so Left gets popped and evaluated first.
        taskStack.add(_ContAltCombine());
        taskStack.add(
          _EvalPattern(
            task.currentRule,
            pattern.right,
            start,
            end,
            task.ruleStart,
            task.minPrecedenceLevel,
          ),
        );
        taskStack.add(
          _EvalPattern(
            task.currentRule,
            pattern.left,
            start,
            end,
            task.ruleStart,
            task.minPrecedenceLevel,
          ),
        );

      case Seq():
        final pivots = bsr.pivotsFor(task.currentRule, start, end);
        taskStack.add(
          _ContSeqLoop(
            task.currentRule,
            pattern,
            start,
            end,
            task.ruleStart,
            task.minPrecedenceLevel,
            pivots.iterator,
          ),
        );

      case Plus():
        final pivots = bsr.pivotsFor(task.currentRule, task.ruleStart, end);
        taskStack.add(
          _ContPlusLoop(
            task.currentRule,
            pattern,
            start,
            end,
            task.ruleStart,
            task.minPrecedenceLevel,
            pivots.iterator,
          ),
        );

      case Star():
        final pivots = bsr.pivotsFor(task.currentRule, task.ruleStart, end);
        taskStack.add(
          _ContStarLoop(
            task.currentRule,
            pattern,
            start,
            end,
            task.ruleStart,
            task.minPrecedenceLevel,
            pivots.iterator,
          ),
        );

      case Conj():
        taskStack.add(
          _ContConjLeft(
            task.currentRule,
            pattern,
            start,
            end,
            task.ruleStart,
            task.minPrecedenceLevel,
          ),
        );
        taskStack.add(
          _EvalPattern(
            task.currentRule,
            pattern.left,
            start,
            end,
            task.ruleStart,
            task.minPrecedenceLevel,
          ),
        );

      case Rule():
        taskStack.add(
          _EvalPattern(
            pattern.symbolId!,
            pattern.body(),
            start,
            end,
            start,
            task.minPrecedenceLevel,
          ),
        );

      case RuleCall(minPrecedenceLevel: var prec, :var rule) ||
          Call(minPrecedenceLevel: var prec, :var rule):
        final effectivePrec = prec ?? task.minPrecedenceLevel;
        final key = '${rule.symbolId!}:$start:$end:${effectivePrec ?? 'null'}';

        taskStack.add(_ContRuleCallFinish());
        taskStack.add(_DoBuildNode(key, rule.symbolId!, start, end, effectivePrec));

      case Action():
        taskStack.add(_ContActionFinish(start, end, pattern.symbolId!));
        taskStack.add(
          _EvalPattern(
            task.currentRule,
            pattern.child,
            start,
            end,
            task.ruleStart,
            task.minPrecedenceLevel,
          ),
        );

      case PrecedenceLabeledPattern():
        if (task.minPrecedenceLevel != null && pattern.precedenceLevel < task.minPrecedenceLevel!) {
          valueStack.add(<ForestNode>[]); // Skip
        } else {
          taskStack.add(
            _EvalPattern(
              task.currentRule,
              pattern.child,
              start,
              end,
              task.ruleStart,
              task.minPrecedenceLevel,
            ),
          );
        }
    }
  }
}

// --- $filename ---
/// State machine-based parser implementation




// ---------------------------------------------------------------------------
// Parse result types — sealed hierarchy replaces dynamic return values
// ---------------------------------------------------------------------------

/// Sealed result type returned by [SMParser.parse] and [SMParser.parseWithForest].
sealed class ParseOutcome {}

/// Returned when parsing fails.
final class ParseError extends ParseOutcome implements Exception {
  final int position;

  ParseError(this.position);

  @override
  String toString() => 'ParseError at position $position';
}

/// Returned when parsing succeeds (marks-based parse).
final class ParseSuccess extends ParseOutcome {
  final ParserResult result;

  ParseSuccess(this.result);
}

/// Returned when parsing succeeds with a full parse forest.
final class ParseForestSuccess extends ParseOutcome {
  final ParseForest forest;

  ParseForestSuccess(this.forest);

  @override
  String toString() => 'ParseForestSuccess(forest=$forest)';
}

// ---------------------------------------------------------------------------

class ParserResult {
  final List<Mark> _rawMarks;

  ParserResult(this._rawMarks);

  List<String> get marks {
    final result = <String>[];
    String? currentStringMark;

    for (final mark in _rawMarks) {
      if (mark is NamedMark) {
        if (currentStringMark != null) {
          result.add(currentStringMark);
          currentStringMark = null;
        }
        result.add(mark.name);
      } else if (mark is StringMark) {
        currentStringMark = (currentStringMark ?? '') + mark.value;
      }
    }

    if (currentStringMark != null) {
      result.add(currentStringMark);
    }

    return result;
  }

  List<List<Object?>> toList() => _rawMarks.map((m) {
    if (m is NamedMark) return m.toList();
    if (m is StringMark) return m.toList();
    return [];
  }).toList();
}

/// Represents a single parse tree derivation
class ParseDerivation {
  final PatternSymbol symbol;
  final int start;
  final int end;
  final List<ParseDerivation> children;

  const ParseDerivation(this.symbol, this.start, this.end, this.children);

  /// Get substring that this derivation matched
  String getMatchedText(String input) {
    if (input.isEmpty || start >= input.length) {
      return '';
    }
    final actualEnd = end > input.length ? input.length : end;
    return input.substring(start, actualEnd);
  }

  /// Convert to flat tree string showing matched content and structure
  /// Example: for input "sss" with grammar S=s|SS|SSS might show (s(ss))
  String toTreeString(String input, [int indent = 0]) {
    final prefix = '  ' * indent;
    final str = '$prefix$this${children.isEmpty ? '  ${input.substring(start, end)}' : ''}\n';
    return str + children.map((c) => c.toTreeString(input, indent + 1)).join('');
  }

  String toPrecedenceString(String input) {
    if (children.isEmpty) {
      return input.substring(start, end);
    }

    List<String> mapped = children
        .where((c) => c.start != c.end)
        .map((c) => c.toPrecedenceString(input))
        .toList();

    if (mapped.length == 1) {
      return mapped.single;
    }

    return "(${mapped.join("")})";
  }

  Object? getSimplified(String input) {
    if (children.isEmpty) {
      return input.substring(start, end);
    }

    if (children.length == 1) {
      return children.single.getSimplified(input);
    }

    return children.map((c) => c.getSimplified(input)).toList();
  }

  /// Pretty print the parse tree
  @override
  String toString() => '$symbol[$start:$end]';
}

/// Represents a parse tree with its evaluated semantic value
class ParseDerivationWithValue<T> {
  final ParseDerivation tree;
  final T value;
  final GrammarInterface? grammar;

  ParseDerivationWithValue(this.tree, this.value, {this.grammar});

  /// Get substring that this derivation matched
  String getMatchedText(String input) => tree.getMatchedText(input);

  /// Get the tree's symbol (as a String ID)
  PatternSymbol get symbol => tree.symbol;

  /// Get the tree's pattern object from the registry (uses grammar context if available)
  Pattern? get pattern {
    if (grammar case var grammar?) {
      return grammar.symbolRegistry[tree.symbol];
    }
    return null;
  }

  /// Get the tree's span
  int get start => tree.start;
  int get end => tree.end;

  /// Get the tree's children
  List<ParseDerivation> get children => tree.children;

  @override
  String toString() => '$symbol[$start:$end]=$value';
}

// ---------------------------------------------------------------------------
// Predicate lookahead buffer — supports unbounded lookahead with buffering
// ---------------------------------------------------------------------------

/// Manages lookahead for predicates without exposing full input during parsing.
/// Dynamically accumulates characters in a buffer and caches predicate results.
/// Supports both synchronous (pre-loaded input) and async (streaming) usage.
class PredicateLookaheadBuffer {
  final List<int> _buffer = []; // Dynamic character buffer
  final Map<(int, String), bool> _predicateCache = {};

  /// Initialize buffer with a complete string (for synchronous parsing)
  void initializeFromString(String input) {
    _buffer.clear();
    _buffer.addAll(input.codeUnits);
  }

  /// Add a single character to the buffer (for streaming)
  void addCodeUnit(int codeUnit) {
    _buffer.add(codeUnit);
  }

  /// Add multiple characters to the buffer
  void addCodeUnits(List<int> codeUnits) {
    _buffer.addAll(codeUnits);
  }

  /// Get a character at position, or -1 if out of bounds
  int codeUnitAt(int position) {
    if (position < 0 || position >= _buffer.length) return -1;
    return _buffer[position];
  }

  /// Check if there are at least [length] characters available from [position]
  bool hasCharsAt(int position, int length) {
    return position >= 0 && position + length <= _buffer.length;
  }

  /// Get substring from [start] to [end], or empty string if out of bounds
  String getSubstring(int start, int end) {
    if (start < 0 || end > _buffer.length || start > end) return '';
    // Convert codeUnits to string
    return String.fromCharCodes(_buffer.sublist(start, end));
  }

  /// Total buffered characters
  int get length => _buffer.length;

  /// Clear the buffer (useful for resetting state)
  void clear() {
    _buffer.clear();
    _predicateCache.clear();
  }

  /// Cache a predicate result to avoid recomputation
  bool cachedPredicateCheck(int position, String patternKey, bool Function() evaluate) {
    final key = (position, patternKey);
    return _predicateCache.putIfAbsent(key, evaluate);
  }

  /// Clear the predicate cache (if needed)
  void clearCache() => _predicateCache.clear();
}

class SMParser {
  final StateMachine stateMachine;
  late final List<Frame> _initialFrames;
  late PredicateLookaheadBuffer _predicateBuffer;

  GrammarInterface get grammar => stateMachine.grammar;

  SMParser(GrammarInterface grammar) : stateMachine = StateMachine(grammar) {
    const initialContext = Context(RootCallerKey(), null);
    final initialFrame = Frame(initialContext);
    initialFrame.nextStates.addAll(stateMachine.initialStates);
    _initialFrames = [initialFrame];
    _predicateBuffer = PredicateLookaheadBuffer();
  }

  /// Create parser from a pre-built state machine (used for imported machines)
  SMParser.fromStateMachine(this.stateMachine) {
    const initialContext = Context(RootCallerKey(), null);
    final initialFrame = Frame(initialContext);
    initialFrame.nextStates.addAll(stateMachine.initialStates);
    _initialFrames = [initialFrame];
    _predicateBuffer = PredicateLookaheadBuffer();
  }

  bool recognize(String input) {
    _predicateBuffer.initializeFromString(input);
    var frames = _initialFrames;
    int position = 0;

    for (final codepoint in input.codeUnits) {
      final stepResult = _processToken(codepoint, position, frames);
      frames = stepResult.nextFrames;
      if (frames.isEmpty) return false;
      position++;
    }

    final lastStep = _processToken(null, position, frames);
    return lastStep.accept;
  }

  ParseOutcome parse(String input) {
    _predicateBuffer.initializeFromString(input);
    var frames = _initialFrames;
    int position = 0;

    for (final codepoint in input.codeUnits) {
      final stepResult = _processToken(codepoint, position, frames);
      frames = stepResult.nextFrames;
      if (frames.isEmpty) {
        return ParseError(position);
      }
      position++;
    }

    final lastStep = _processToken(null, position, frames);

    if (lastStep.accept) {
      return ParseSuccess(ParserResult(lastStep.marks));
    } else {
      return ParseError(position);
    }
  }

  /// Parse with forest extraction enabled.
  ///
  /// Internally uses BSR (Binarised Shared Representation) recorded during
  /// parsing to restrict the SPPF construction to spans proven reachable by
  /// the parser, rather than exhaustively searching the whole grammar.
  ParseOutcome parseWithForest(String input) {
    _predicateBuffer.initializeFromString(input);
    final bsrOutcome = parseToBsr(input);
    if (bsrOutcome is BsrParseError) {
      return ParseError(bsrOutcome.position);
    }

    final bsrSuccess = bsrOutcome as BsrParseSuccess;
    final bsrSet = bsrSuccess.bsrSet;
    final startRule = stateMachine.grammar.startCall.rule;
    final nodeManager = ForestNodeManager();
    final root = bsrSet.buildSppf(grammar, startRule, input, nodeManager);
    final effectiveRoot = root ?? nodeManager.symbolic(0, input.length, startRule.symbolId!);
    final forest = ParseForest(nodeManager, effectiveRoot, []);
    return ParseForestSuccess(forest);
  }

  /// Parse a stream of input chunks with forest extraction.
  ///
  /// Processes input incrementally as chunks arrive without buffering the entire
  /// stream in memory. Uses a bounded sliding-window buffer for predicate lookahead
  /// (default 1MB). Suitable for streaming large files.
  ///
  /// WARNING: If the grammar has predicates that require lookahead beyond the
  /// buffer window, results may be incorrect. Adjust [lookaheadWindowSize] if needed.
  Future<ParseOutcome> parseWithForestAsync(
    Stream<String> input, {
    int lookaheadWindowSize = 1048576,
  }) {
    _predicateBuffer.clear();

    final completer = Completer<ParseOutcome>();
    var frames = _initialFrames;
    int globalPosition = 0;

    // Bounded buffer for lookahead: prevents unbounded memory growth
    final lookaheadWindow = <int>[];

    // Keep all input for a second pass to get marks (required for correct SPPF construction)
    final allInput = <int>[];

    // BSR recording happens as we parse
    final bsr = BsrSet();

    input.listen(
      (chunk) {
        try {
          // Feed chunk data into the parser token-by-token
          for (final codeUnit in chunk.codeUnits) {
            // Store for second pass
            allInput.add(codeUnit);

            // Maintain bounded window: keep only recent data for lookahead
            lookaheadWindow.add(codeUnit);
            if (lookaheadWindow.length > lookaheadWindowSize) {
              lookaheadWindow.removeAt(0);
            }

            // Update the predicate buffer for this token
            _predicateBuffer._buffer.clear();
            _predicateBuffer._buffer.addAll(lookaheadWindow);

            // Process this token with BSR recording
            final stepResult = _processToken(codeUnit, globalPosition, frames, bsr: bsr);
            frames = stepResult.nextFrames;

            // If parsing fails, complete with error
            if (frames.isEmpty) {
              completer.complete(ParseError(globalPosition));
              return;
            }

            globalPosition++;
          }
        } catch (e) {
          completer.completeError(e);
        }
      },
      onError: (error) {
        if (!completer.isCompleted) {
          completer.completeError(error);
        }
      },
      onDone: () {
        // Defer finalization to avoid blocking
        Future.microtask(() {
          try {
            if (completer.isCompleted) return;

            // Process end-of-stream token
            final lastStep = _processToken(null, globalPosition, frames, bsr: bsr);

            if (lastStep.accept) {
              // Now do a second pass over the buffered input to get marks
              // (matches the sync algorithm's approach)
              _predicateBuffer.initializeFromString(String.fromCharCodes(allInput));
              var marksFrames = _initialFrames;
              for (int i = 0; i < allInput.length; i++) {
                final stepResult = _processToken(allInput[i], i, marksFrames, bsr: null);
                marksFrames = stepResult.nextFrames;
              }
              final marksStep = _processToken(null, allInput.length, marksFrames, bsr: null);

              // Build SPPF from the recorded BSR
              final startRule = stateMachine.grammar.startCall.rule;
              final nodeManager = ForestNodeManager();
              final fullInput = String.fromCharCodes(allInput);
              final root = bsr.buildSppf(grammar, startRule, fullInput, nodeManager);
              final effectiveRoot =
                  root ?? nodeManager.symbolic(0, globalPosition, startRule.symbolId!);
              final forest = ParseForest(nodeManager, effectiveRoot, marksStep.marks);
              completer.complete(ParseForestSuccess(forest));
            } else {
              completer.complete(ParseError(globalPosition));
            }
          } catch (e) {
            if (!completer.isCompleted) {
              completer.completeError(e);
            }
          }
        });
      },
    );

    return completer.future;
  }

  /// Parse and return the BSR set of all proven rule-completion spans.
  ///
  /// Returns [BsrParseSuccess] with the [BsrSet] on success, or
  /// [BsrParseError] if the input does not conform to the grammar.
  BsrParseOutcome parseToBsr(String input) {
    _predicateBuffer.initializeFromString(input);
    final bsr = BsrSet();
    var frames = _initialFrames;
    int position = 0;

    for (final codepoint in input.codeUnits) {
      final stepResult = _processToken(codepoint, position, frames, input: input, bsr: bsr);
      frames = stepResult.nextFrames;
      if (frames.isEmpty) {
        return BsrParseError(position);
      }
      position++;
    }

    final lastStep = _processToken(null, position, frames, input: input, bsr: bsr);

    if (lastStep.accept) {
      return BsrParseSuccess(bsr, lastStep.marks);
    } else {
      return BsrParseError(position);
    }
  }

  /// Count all possible parse trees without building them
  int countAllParses(String input) {
    final startRule = stateMachine.grammar.startCall.rule;
    return _countDerivations(startRule, input, 0, input.length, {}, {});
  }

  /// Enumerate all possible parse trees lazily, yielding each as a [ParseDerivation].
  Iterable<ParseDerivation> enumerateAllParses(String input) {
    final startRule = stateMachine.grammar.startCall.rule;
    return _enumerateDerivations(startRule, input, 0, input.length, {}, {});
  }

  /// Enumerate all possible parse trees with evaluated semantic values.
  /// Actions are executed bottom-up with child results.
  Iterable<ParseDerivationWithValue<dynamic>> enumerateAllParsesWithResults(String input) sync* {
    for (final derivation in enumerateAllParses(input)) {
      final value = evaluateParseDerivation(derivation, input);
      yield ParseDerivationWithValue(derivation, value, grammar: grammar);
    }
  }

  /// Convert a [ParseTree] (forest representation) to a [ParseDerivation] (enumeration representation).
  static ParseDerivation parseTreeToDerivation(ParseTree tree, String input) {
    final childDerivations = tree
        .children //
        .map((c) => parseTreeToDerivation(c, input))
        .toList();

    return ParseDerivation(tree.node.symbol, tree.node.start, tree.node.end, childDerivations);
  }

  int _countDerivations(
    Rule rule,
    String input,
    int start,
    int end,
    Map<String, int> memo,
    Map<String, bool> inProgress,
  ) {
    final key = '${rule.name}:$start:$end';

    if (memo.containsKey(key)) {
      return memo[key]!;
    }

    if (inProgress[key] == true) {
      return 0; // Avoid cycles
    }

    if (start == end) {
      try {
        final isEmpty = rule.body().empty();
        final result = isEmpty ? 1 : 0;
        memo[key] = result;
        return result;
      } catch (_) {
        memo[key] = 0;
        return 0;
      }
    }

    inProgress[key] = true;
    int totalCount = _countAlternatives(rule.body(), input, start, end, memo, inProgress);
    inProgress[key] = false;
    memo[key] = totalCount;
    return totalCount;
  }

  int _countAlternatives(
    Pattern pattern,
    String input,
    int start,
    int end,
    Map<String, int> memo,
    Map<String, bool> inProgress,
  ) {
    if (pattern is Token) {
      if (start + 1 == end && pattern.match(input.codeUnitAt(start))) {
        return 1;
      }
      return 0;
    }

    if (pattern is Eps) {
      return start == end ? 1 : 0;
    }

    if (pattern is Marker) {
      return _countAlternatives(Eps(), input, start, end, memo, inProgress);
    }

    if (pattern is Alt) {
      return _countAlternatives(pattern.left, input, start, end, memo, inProgress) +
          _countAlternatives(pattern.right, input, start, end, memo, inProgress);
    }

    if (pattern is Seq) {
      int totalCount = 0;
      // Try all split points
      for (int mid = start; mid <= end; mid++) {
        final leftCount = _countAlternatives(pattern.left, input, start, mid, memo, inProgress);
        if (leftCount > 0) {
          final rightCount = _countAlternatives(pattern.right, input, mid, end, memo, inProgress);
          totalCount += leftCount * rightCount;
        }
      }
      return totalCount;
    }

    if (pattern is Plus) {
      // At least one match
      int totalCount = 0;
      for (int mid = start + 1; mid <= end; mid++) {
        final childCount = _countAlternatives(pattern.child, input, start, mid, memo, inProgress);
        if (childCount > 0) {
          final starCount = _countStar(pattern.child, input, mid, end, memo, inProgress);
          totalCount += childCount * starCount;
        }
      }
      return totalCount;
    }

    if (pattern is Call) {
      return _countDerivations(pattern.rule, input, start, end, memo, inProgress);
    }

    if (pattern is RuleCall) {
      return _countDerivations(pattern.rule, input, start, end, memo, inProgress);
    }

    if (pattern is Action) {
      // Action wraps another pattern - just delegate to unwrapped pattern
      return _countAlternatives(pattern.child, input, start, end, memo, inProgress);
    }

    if (pattern is Star) {
      return _countStar(pattern.child, input, start, end, memo, inProgress);
    }

    if (pattern is Conj) {
      if (start + 1 == end &&
          pattern.left.match(input.codeUnitAt(start)) &&
          pattern.right.match(input.codeUnitAt(start))) {
        return 1;
      }
      return 0;
    }

    if (pattern is PrecedenceLabeledPattern) {
      return _countAlternatives(pattern.child, input, start, end, memo, inProgress);
    }

    if (pattern is And || pattern is Not) {
      if (start == end &&
          _checkPredicatePattern(
                pattern is And ? pattern.pattern : (pattern as Not).pattern,
                start,
              ) ==
              (pattern is And)) {
        return 1;
      }
      return 0;
    }

    return 0;
  }

  // Count zero or more matches of a pattern
  int _countStar(
    Pattern pattern,
    String input,
    int start,
    int end,
    Map<String, int> memo,
    Map<String, bool> inProgress,
  ) {
    if (start == end) {
      return 1; // Zero matches
    }

    int totalCount = 1; // Zero matches at current position

    // One or more matches
    for (int mid = start + 1; mid <= end; mid++) {
      final childCount = _countAlternatives(pattern, input, start, mid, memo, inProgress);
      if (childCount > 0) {
        final restCount = _countStar(pattern, input, mid, end, memo, inProgress);
        totalCount += childCount * restCount;
      }
    }

    return totalCount;
  }

  Iterable<ParseDerivation> _enumerateDerivations(
    Rule rule,
    String input,
    int start,
    int end,
    Map<String, List<ParseDerivation>?> memo,
    Map<String, bool> inProgress, {
    int? minPrecedenceLevel,
  }) sync* {
    final key =
        '${rule.name}:$start:$end${minPrecedenceLevel != null ? ':min$minPrecedenceLevel' : ''}';

    // If we've already computed this span, replay from cache
    if (memo.containsKey(key)) {
      yield* memo[key]!;
      return;
    }

    if (inProgress[key] == true) {
      return; // Avoid cycles
    }

    if (start == end) {
      try {
        if (rule.body().empty()) {
          final d = ParseDerivation(rule.symbolId!, start, end, []);
          memo[key] = [d];
          yield d;
        } else {
          memo[key] = [];
        }
      } catch (_) {
        memo[key] = [];
      }
      return;
    }

    inProgress[key] = true;
    final cache = <ParseDerivation>[];
    for (final d in _enumerateAlternatives(
      rule.body(),
      input,
      start,
      end,
      memo,
      inProgress,
      minPrecedenceLevel: minPrecedenceLevel,
    )) {
      cache.add(d);
      yield d;
    }
    inProgress[key] = false;
    memo[key] = cache;
  }

  Iterable<ParseDerivation> _enumerateAlternatives(
    Pattern pattern,
    String input,
    int start,
    int end,
    Map<String, List<ParseDerivation>?> memo,
    Map<String, bool> inProgress, {
    int? minPrecedenceLevel,
  }) sync* {
    if (pattern is Token) {
      if (start + 1 == end && pattern.match(input.codeUnitAt(start))) {
        yield ParseDerivation(pattern.symbolId!, start, end, []);
      }
      return;
    }

    if (pattern is Eps) {
      if (start == end) yield ParseDerivation(pattern.symbolId, start, end, []);
      return;
    }

    if (pattern is Marker) {
      if (start == end) yield ParseDerivation(pattern.symbolId!, start, end, []);
      return;
    }

    if (pattern is PrecedenceLabeledPattern) {
      // Check if this alternative meets the minimum precedence level
      if (minPrecedenceLevel != null && pattern.precedenceLevel < minPrecedenceLevel) {
        // Skip this alternative - it doesn't meet the precedence requirement
        return;
      }
      // Forward the minPrecedenceLevel to the wrapped pattern
      yield* _enumerateAlternatives(
        pattern.child,
        input,
        start,
        end,
        memo,
        inProgress,
        minPrecedenceLevel: minPrecedenceLevel,
      );
      return;
    }

    if (pattern is Alt) {
      final key = '${pattern.hashCode}:$start:$end:${minPrecedenceLevel ?? ""}';
      if (inProgress[key] == true) return;
      inProgress[key] = true;
      yield* _enumerateAlternatives(
        pattern.left,
        input,
        start,
        end,
        memo,
        inProgress,
        minPrecedenceLevel: minPrecedenceLevel,
      );
      yield* _enumerateAlternatives(
        pattern.right,
        input,
        start,
        end,
        memo,
        inProgress,
        minPrecedenceLevel: minPrecedenceLevel,
      );
      inProgress[key] = false;
      return;
    }

    if (pattern is Seq) {
      // CFG sequence: enumerate ALL splits where both left and right match
      for (int mid = start; mid <= end; mid++) {
        final leftList = _enumerateAlternatives(
          pattern.left,
          input,
          start,
          mid,
          memo,
          inProgress,
          minPrecedenceLevel: minPrecedenceLevel,
        ).toList();
        if (leftList.isEmpty) continue;

        final rightList = _enumerateAlternatives(
          pattern.right,
          input,
          mid,
          end,
          memo,
          inProgress,
          minPrecedenceLevel: minPrecedenceLevel,
        ).toList();
        if (rightList.isEmpty) continue;

        for (final left in leftList) {
          for (final right in rightList) {
            yield ParseDerivation(pattern.symbolId!, start, end, [left, right]);
          }
        }
      }
      return;
    }

    if (pattern is Plus) {
      for (int mid = start + 1; mid <= end; mid++) {
        final childList = _enumerateAlternatives(
          pattern.child,
          input,
          start,
          mid,
          memo,
          inProgress,
          minPrecedenceLevel: minPrecedenceLevel,
        ).toList();
        if (childList.isEmpty) continue;
        for (final child in childList) {
          for (final star in _enumerateStar(
            pattern.child,
            input,
            mid,
            end,
            '${pattern.child}*',
            memo,
            inProgress,
          )) {
            // Only yield if plus covers the full requested span
            if (star.end == end) {
              yield ParseDerivation(pattern.symbolId!, start, end, [child, star]);
            }
          }
        }
      }
      return;
    }

    if (pattern is Call) {
      // Check precedence constraint on the Call pattern
      final constraint = pattern.minPrecedenceLevel;
      yield* _enumerateDerivations(
        pattern.rule,
        input,
        start,
        end,
        memo,
        inProgress,
        minPrecedenceLevel: constraint,
      );
      return;
    }

    if (pattern is RuleCall) {
      // Check precedence constraint on the RuleCall pattern
      final constraint = pattern.minPrecedenceLevel;
      yield* _enumerateDerivations(
        pattern.rule,
        input,
        start,
        end,
        memo,
        inProgress,
        minPrecedenceLevel: constraint,
      );
      return;
    }

    if (pattern is Action) {
      for (final child in _enumerateAlternatives(
        pattern.child,
        input,
        start,
        end,
        memo,
        inProgress,
        minPrecedenceLevel: minPrecedenceLevel,
      )) {
        yield ParseDerivation(pattern.symbolId!, start, end, [child]);
      }
      return;
    }

    if (pattern is And) {
      // Positive lookahead: check if pattern matches at start position without consuming
      if (_checkPredicatePattern(pattern.pattern, start)) {
        // Predicate succeeded - yield empty derivation (zero-width match)
        yield ParseDerivation(pattern.symbolId!, start, start, []);
      }
      return;
    }

    if (pattern is Not) {
      // Negative lookahead: check if pattern does NOT match at start position
      if (!_checkPredicatePattern(pattern.pattern, start)) {
        // Predicate succeeded - yield empty derivation (zero-width match)
        yield ParseDerivation(pattern.symbolId!, start, start, []);
      }
      return;
    }

    if (pattern is Star) {
      yield* _enumerateStar(pattern.child, input, start, end, 'Star', memo, inProgress);
      return;
    }
    if (pattern is Conj) {
      if (start + 1 == end &&
          pattern.left.match(input.codeUnitAt(start)) &&
          pattern.right.match(input.codeUnitAt(start))) {
        yield ParseDerivation(pattern.symbolId!, start, end, []);
      }
      return;
    }
  }

  Iterable<ParseDerivation> _enumerateStar(
    Pattern pattern,
    String input,
    int start,
    int end,
    String symbol,
    Map<String, List<ParseDerivation>?> memo,
    Map<String, bool> inProgress,
  ) sync* {
    if (start == end) {
      yield ParseDerivation(pattern.symbolId!, start, end, []);
      return;
    }

    // PEG greedy matching: try longest match first
    for (int mid = end; mid > start; mid--) {
      final childList = _enumerateAlternatives(
        pattern,
        input,
        start,
        mid,
        memo,
        inProgress,
      ).toList();
      if (childList.isNotEmpty) {
        for (final child in childList) {
          for (final star in _enumerateStar(pattern, input, mid, end, symbol, memo, inProgress)) {
            // Use the actual end position from the star tree, not the requested 'end'
            final actualEnd = star.end;
            yield ParseDerivation(pattern.symbolId!, start, actualEnd, [child, star]);
          }
        }
        return; // Only use the first (longest) match - PEG greedy semantics
      }
    }

    // No match found - zero matches
    yield ParseDerivation(pattern.symbolId!, start, start, []);
  }

  /// Evaluate a [ParseDerivation] with evaluated semantic values.
  Object? evaluateParseDerivation(ParseDerivation derivation, String input) {
    return _evaluateParseDerivation(derivation, input);
  }

  /// Directly evaluate a [ParseTree] extracted from the forest.
  Object? evaluateParseTree(ParseTree tree, String input) {
    return _evaluateParseDerivation(parseTreeToDerivation(tree, input), input);
  }

  Object? _evaluateParseDerivation(ParseDerivation tree, String input) {
    switch (grammar.symbolRegistry[tree.symbol]) {
      case Token pattern:
        if (tree.start + 1 == tree.end && pattern.match(input.codeUnitAt(tree.start))) {
          final evaluated = tree.getMatchedText(input);
          return evaluated;
        }
      case Marker pattern:
        return NamedMark(pattern.name, tree.start);
      case Eps():
        return "";
      case Alt():
        // One of the alternatives matched - evaluate that child
        if (tree.children.isNotEmpty) {
          return _evaluateParseDerivation(tree.children[0], input);
        }
        return null;
      case Seq():
        // Sequence: evaluate left and right children
        final results = <dynamic>[];
        for (final child in tree.children) {
          final childValue = _evaluateParseDerivation(child, input);
          results.add(childValue);
        }
        return results;
      case Conj():
        // Conjunction: both patterns match the same token
        final codeUnit = input.codeUnitAt(tree.start);
        return String.fromCharCode(codeUnit);
      case Plus():
      case Star():
        // One/Zero or more: collect all child results into a list.
        // We avoid flattening sequences (lists) from the body match.
        final results = <dynamic>[];
        if (tree.children.isNotEmpty) {
          print((children: tree.children));
          // First child is the 'head' element
          results.add(_evaluateParseDerivation(tree.children[0], input));
          // Second child (if any) is the rest of the repetition (tail)
          if (tree.children.length > 1) {
            final rest = _evaluateParseDerivation(tree.children[1], input);
            if (rest is List) {
              results.addAll(rest);
            } else if (rest != "") {
              results.add(rest);
            }
          }
        }
        return results;
      case And():
        // Positive lookahead: zero-width, return empty list
        return [];
      case Not():
        // Negative lookahead: zero-width, return empty list
        return [];
      case Rule():
        // Evaluate the rule's body
        return _evaluateParseDerivation(
          tree.children.isNotEmpty
              ? tree.children[0]
              : ParseDerivation(Eps().symbolId, tree.start, tree.end, []),
          input,
        );
      case RuleCall _:
        // Recursively evaluate the referenced rule
        if (tree.children.isNotEmpty) {
          return _evaluateParseDerivation(tree.children[0], input);
        }
        return null;
      case Call _:
        // Recursively evaluate the referenced rule
        if (tree.children.isNotEmpty) {
          return _evaluateParseDerivation(tree.children[0], input);
        }
        return null;
      case Action action:
        // Evaluate the child and apply the semantic action
        assert(tree.children.length == 1, "Action Nodes should only have one child.");

        final childResults = <dynamic>[];
        for (final child in tree.children) {
          final childValue = _evaluateParseDerivation(child, input);
          childResults.add(childValue);
        }
        final span = tree.getMatchedText(input);
        if (childResults.length == 1 && childResults.single is List) {
          return action.callback(span, childResults.single);
        }
        return action.callback(span, childResults);
      case PrecedenceLabeledPattern():
        // Unwrap and evaluate the child pattern
        if (tree.children.isNotEmpty) {
          return _evaluateParseDerivation(tree.children[0], input);
        }
        return null;
      case null:
        throw StateError("Tried to evaluate using an invalid symbol.");
    }

    return null;
  }

  Step _processToken(
    int? token,
    int position,
    List<Frame> frames, {
    String input = '',
    BsrSet? bsr,
  }) {
    final step = Step(this, token, position, input: input, bsr: bsr, buffer: _predicateBuffer);
    for (final frame in frames) {
      step._processFrame(frame);
    }

    return step;
  }

  /// Check if a pattern matches at a given position in the input without consuming.
  /// Used for AND/NOT lookahead predicates.
  ///
  /// This is a fast check that determines if a pattern would match at startPos
  /// without actually advancing the parser state.
  bool checkPatternAtPosition(Pattern pattern, String inputStr, int startPos) {
    _predicateBuffer.initializeFromString(inputStr);
    return _checkPredicatePattern(pattern, startPos);
  }

  /// Internal: recursive predicate pattern checking (uses buffer stored on parser)
  bool _checkPredicatePattern(Pattern pattern, int startPos) {
    // Base cases
    if (pattern is Token) {
      final codeUnit = _predicateBuffer.codeUnitAt(startPos);
      if (codeUnit >= 0) {
        return pattern.match(codeUnit);
      }
      return false;
    }

    if (pattern is Eps) {
      return true;
    }

    if (pattern is Marker) {
      return true;
    }

    if (pattern is Alt) {
      return _checkPredicatePattern(pattern.left, startPos) ||
          _checkPredicatePattern(pattern.right, startPos);
    }

    if (pattern is Seq) {
      return _checkPredicateSeq(pattern.left, pattern.right, startPos);
    }

    if (pattern is And) {
      return _checkPredicatePattern(pattern.pattern, startPos);
    }

    if (pattern is Not) {
      return !_checkPredicatePattern(pattern.pattern, startPos);
    }

    if (pattern is Call || pattern is RuleCall) {
      Rule rule = pattern is Call ? pattern.rule : (pattern as RuleCall).rule;
      return _ruleMatchesAtPosition(rule, startPos);
    }

    if (pattern is Action) {
      return _checkPredicatePattern(pattern.child, startPos);
    }

    // Default: assume matches
    return true;
  }

  /// Check if a sequence matches: left followed by right
  bool _checkPredicateSeq(Pattern left, Pattern right, int startPos) {
    // Determine how much 'left' consumes
    final leftLen = _estimatePatternLength(left, startPos);
    if (leftLen < 0) return false;
    return _checkPredicatePattern(right, startPos + leftLen);
  }

  /// Estimate how many characters a pattern would match.
  /// Returns >= 0 if matches, < 0 if doesn't match.
  int _estimatePatternLength(Pattern pattern, int startPos) {
    if (startPos > _predicateBuffer.length) return -1;

    if (pattern is Token) {
      if (_checkPredicatePattern(pattern, startPos)) {
        return 1;
      }
      return -1;
    }

    if (pattern is Eps) {
      return 0;
    }

    if (pattern is Marker) {
      return 0;
    }

    if (pattern is Alt) {
      int leftLen = _estimatePatternLength(pattern.left, startPos);
      if (leftLen >= 0) return leftLen;
      return _estimatePatternLength(pattern.right, startPos);
    }

    if (pattern is And || pattern is Not) {
      // Predicates are zero-width
      return 0;
    }

    if (pattern is Call || pattern is RuleCall) {
      // For rules, we don't know the length - be conservative
      // A better implementation would parse to determine length
      return 0;
    }

    if (pattern is Action) {
      return _estimatePatternLength(pattern.child, startPos);
    }

    // Default: unknown
    return -1;
  }

  /// Check if a rule's body matches at the given position
  bool _ruleMatchesAtPosition(Rule rule, int startPos) {
    if (startPos >= _predicateBuffer.length && !rule.body().empty()) {
      return false;
    }

    // Check if the rule body can match from startPos to any end position
    try {
      // Try to find at least one valid match
      for (int endPos = startPos; endPos <= _predicateBuffer.length; endPos++) {
        if (_patternCanMatch(rule.body(), startPos, endPos)) {
          return true;
        }
      }
      return false;
    } catch (_) {
      // If anything goes wrong, be conservative
      return true;
    }
  }

  /// Check if a pattern can match the span [start, end)
  bool _patternCanMatch(Pattern pattern, int start, int end) {
    if (pattern is Token) {
      return start + 1 == end && pattern.match(_predicateBuffer.codeUnitAt(start));
    }

    if (pattern is Eps) {
      return start == end;
    }

    if (pattern is Marker) {
      return start == end;
    }

    if (pattern is Alt) {
      return _patternCanMatch(pattern.left, start, end) ||
          _patternCanMatch(pattern.right, start, end);
    }

    if (pattern is Seq) {
      // Try all split points
      for (int mid = start; mid <= end; mid++) {
        if (_patternCanMatch(pattern.left, start, mid) &&
            _patternCanMatch(pattern.right, mid, end)) {
          return true;
        }
      }
      return false;
    }

    if (pattern is Plus) {
      // At least one match
      if (start == end) return false;
      for (int mid = start + 1; mid <= end; mid++) {
        if (_patternCanMatch(pattern.child, start, mid)) {
          // Check if rest can be matched by zero or more
          if (mid == end || _patternCanMatchStar(pattern.child, mid, end)) {
            return true;
          }
        }
      }
      return false;
    }

    if (pattern is Star) {
      // Zero or more matches
      if (start == end) return true; // Zero matches always succeeds

      // Try one or more matches
      for (int mid = start + 1; mid <= end; mid++) {
        if (_patternCanMatch(pattern.child, start, mid)) {
          // Check if rest can be matched by zero or more
          if (mid == end || _patternCanMatchStar(pattern.child, mid, end)) {
            return true;
          }
        }
      }
      return false;
    }

    if (pattern is And || pattern is Not) {
      return start == end;
    }

    if (pattern is Call || pattern is RuleCall) {
      Rule rule = pattern is Call ? pattern.rule : (pattern as RuleCall).rule;
      return _patternCanMatch(rule.body(), start, end);
    }

    if (pattern is Action) {
      return _patternCanMatch(pattern.child, start, end);
    }

    return false;
  }

  /// Check if a pattern can match zero or more times in the span [start, end)
  bool _patternCanMatchStar(Pattern pattern, int start, int end) {
    if (start == end) return true; // Zero matches

    // Try one match
    for (int mid = start + 1; mid <= end; mid++) {
      if (_patternCanMatch(pattern, start, mid) && _patternCanMatchStar(pattern, mid, end)) {
        return true;
      }
    }

    return false;
  }
}

// ---------------------------------------------------------------------------
// Internal parsing machinery
// ---------------------------------------------------------------------------

/// Strongly typed key to identify a call site.
sealed class CallerKey {
  const CallerKey();
}

/// Represents the root call context.
final class RootCallerKey extends CallerKey {
  const RootCallerKey();

  @override
  int get hashCode => 0;

  @override
  bool operator ==(Object other) => other is RootCallerKey;
}

/// Caller tracking for rule returns
final class Caller extends CallerKey {
  final Rule rule;
  final Pattern pattern;

  /// Key is a (caller, nextState) pair encoded as a two-element list.
  final Map<(CallerKey, State), List<Context>> _grouped = {};

  /// The input position at which the associated rule was invoked.
  /// Set once at CallAction time; used by ReturnAction to record BSR entries.
  int? callStart;

  Caller(this.rule, this.pattern);

  void addReturn(Context context, State nextState) {
    final key = (context.caller, nextState);
    _grouped.putIfAbsent(key, () => []).add(context);
  }

  void forEach(void Function(CallerKey, State, Context) callback) {
    for (final MapEntry(key: (caller, nextState), value: contexts) in _grouped.entries) {
      for (final context in contexts) {
        callback(caller, nextState, context);
      }
    }
  }
}

/// Context for parsing (tracks marks, callers, and BSR call-start position).
class Context {
  final CallerKey caller;
  final GlushList<Mark>? marks;

  /// The input position at which the rule associated with this context
  /// was invoked.  Used to record BSR rule-completion entries.
  final int? callStart;

  /// The input position where the last matched symbol started.
  /// Used for midPoint in BSR nodes.
  final int? pivot;

  /// The computed semantic value at this point in parsing.
  /// Updated as semantic actions are evaluated during parsing.
  final Object? semanticValue;

  const Context(this.caller, this.marks, [this.callStart, this.pivot, this.semanticValue]);
}

/// Frame for managing parsing states
class Frame {
  final Context context;
  final Set<State> nextStates;

  Frame(this.context) : nextStates = {};

  Frame copy() => Frame(context);

  CallerKey get caller => context.caller;
  GlushList<Mark>? get marks => context.marks;
}

/// Single step in parsing
class Step {
  final SMParser parser;
  final int? token;
  final int position;
  final String input;

  /// Optional BSR set to populate with rule-completion entries. When null,
  /// BSR recording is skipped (used by the plain recognize/parse paths).
  final BsrSet? bsr;

  /// Predicate lookahead buffer for checking patterns without full input access
  final PredicateLookaheadBuffer buffer;

  final List<Frame> nextFrames = [];
  final Map<(Rule, Pattern), Caller> _callers = {};
  final Set<CallerKey> _returnedCallers = {};
  final List<Context> _acceptedContexts = [];

  // /// Frames created during CPS processing that need conditional adding to nextFrames
  // final Set<Frame> _localFramesInCurrentProcessing = {};

  Step(
    this.parser,
    this.token,
    this.position, {
    required this.input,
    this.bsr,
    required this.buffer,
  });

  bool get accept => _acceptedContexts.isNotEmpty;

  List<Mark> get marks {
    final markList = _acceptedContexts[0].marks;
    if (markList == null) return [];
    return markList.toList().cast<Mark>();
  }

  void _withFrame(Context context, void Function(Frame) callback) {
    final frame = Frame(context);
    callback(frame);
    if (frame.nextStates.isNotEmpty) {
      nextFrames.add(frame);
    }
  }

  void _process(Frame frame, State state) {
    for (final action in state.actions) {
      switch (action) {
        case SemanticAction():
          // Evaluate semantic action during parsing
          // Extract child results from marks (StringMark values)
          final marks = frame.marks?.toList() ?? [];
          final childResults = <Object?>[];
          int spanStart = position;
          int spanEnd = position;

          for (final mark in marks) {
            if (mark is StringMark) {
              childResults.add(mark.value);
              spanStart = spanStart > mark.position ? mark.position : spanStart;
              spanEnd = mark.position + 1; // Update end position
            } else if (mark is NamedMark) {
              spanStart = spanStart > mark.position ? mark.position : spanStart;
              spanEnd = spanEnd < mark.position ? mark.position : spanEnd;
            }
          }

          // Compute the span string from input
          final span = spanStart < input.length && spanEnd <= input.length
              ? input.substring(spanStart, spanEnd)
              : '';

          // Call the semantic action callback with computed span and child results
          final computedValue = action.callback(span, childResults);

          // Create new context with computed semantic value
          final semanticCtx = Context(
            frame.caller,
            frame.marks,
            frame.context.callStart,
            frame.context.pivot,
            computedValue,
          );

          _withFrame(semanticCtx, (frame) {
            _process(frame, action.nextState);
          });
        case TokenAction():
          if (token case var token? when action.pattern.match(token)) {
            // If token matches, add a StringMark with the captured token if not ExactToken
            // So ranges and 'any' tokens are captured into the marks array too
            var newMarks = frame.marks;
            if (action.pattern case Token(:var choice) when choice is! ExactToken) {
              final strMark = StringMark(String.fromCharCode(token), position);
              newMarks = (newMarks ?? const GlushList.empty()).add(strMark);
            }

            final bsrSet = bsr;
            if (bsrSet != null && frame.caller is Caller) {
              final rule = (frame.caller as Caller).rule;
              bsrSet.add(
                rule.symbolId!,
                frame.context.callStart!,
                position, // Use current position as pivot for this token
                position + 1,
              );
            }

            final nextFrame = Frame(
              Context(frame.caller, newMarks, frame.context.callStart, position + 1),
            );
            nextFrame.nextStates.add(action.nextState);
            nextFrames.add(nextFrame);
            // TokenAction does NOT enqueue - it defers to next token step
          }
        case MarkAction():
          final mark = NamedMark(action.name, position);
          final markCtx = Context(
            frame.caller,
            (frame.marks ?? const GlushList.empty()).add(mark),
            frame.context.callStart,
            frame.context.pivot,
          );

          final bsrSet = bsr;
          if (bsrSet != null && frame.caller is Caller) {
            final rule = (frame.caller as Caller).rule;
            bsrSet.add(rule.symbolId!, frame.context.callStart!, position, position);
          }

          _withFrame(markCtx, (nextFrame) {
            _process(nextFrame, action.nextState);
          });
        case PredicateAction():
          // Predicate checking (lookahead without consumption)
          // Buffer ensures we have the data needed for lookahead
          bool predicateMatches = parser._checkPredicatePattern(action.pattern, position);

          // For AND (&pattern), continue if pattern matches
          // For NOT (!pattern), continue if pattern does NOT match
          final shouldContinue = action.isAnd ? predicateMatches : !predicateMatches;

          if (shouldContinue) {
            // Predicate succeeded - enqueue next state processing
            // Zero-width: processed with the same token in this frame step
            _withFrame(frame.context, (nextFrame) {
              _process(nextFrame, action.nextState);
            });
          }
        // If predicate failed, we simply don't enqueue (backtrack)
        case CallAction():
          final rule = action.rule;
          final pattern = action.pattern;
          final key = (rule, pattern);
          final isExecuted = _callers.containsKey(key);
          final caller = _callers.putIfAbsent(key, () => Caller(rule, pattern));

          caller.addReturn(frame.context, action.returnState);
          if (!isExecuted) {
            // Store callStart on the Caller so ReturnAction can emit BSR entries.
            caller.callStart = position;
            final callCtx = Context(caller, const GlushList.empty(), position);
            // Create local frame that will be conditionally added to nextFrames

            _withFrame(callCtx, (nextFrame) {
              for (final firstState in parser.stateMachine.ruleFirst[rule] ?? []) {
                _process(nextFrame, firstState);
              }
            });
          }
        case ReturnAction():
          final rule = action.rule;

          if (token != null && rule.guard != null && !rule.guard!.match(token)) {
            continue;
          }

          // Record BSR rule-completion entry BEFORE the ambiguity guard,
          // so every distinct (rule, callStart, position) span is captured.
          // The _returnedCallers guard below is only for parsing-state correctness.
          final callStart =
              frame.context.callStart ??
              (frame.caller is Caller ? (frame.caller as Caller).callStart : null);
          final lastPivot = frame.context.pivot;
          if ((bsr, callStart, lastPivot ?? callStart) case (
            var bsr?,
            var callStart?,
            var pivot?,
          )) {
            bsr.add(rule.symbolId!, callStart, pivot, position);
          }

          final caller = frame.caller;

          // Record BSR entries for all parent rules being returned to.
          // This must happen BEFORE the ambiguity guard because different
          // derivations of 'rule' might return to the same 'caller' context,
          // providing alternative pivots for the parent rule's sequence.
          final bsrSet = bsr;
          if (bsrSet != null && caller is Caller) {
            caller.forEach((ccaller, nextState, ccontext) {
              if (ccaller is Caller) {
                bsrSet.add(
                  ccaller.rule.symbolId!,
                  ccontext.callStart!,
                  caller.callStart!,
                  position,
                );
              }
            });
          }

          // Simple ambiguity handling: only process each caller once
          final shouldProcess = _returnedCallers.add(caller);
          if (!shouldProcess) continue;

          if (caller is Caller) {
            caller.forEach((ccaller, nextState, ccontext) {
              final nextMarks = ccontext.marks == null
                  ? frame.marks
                  : GlushList.branched<Mark>([
                      ccontext.marks!,
                    ]).addList(frame.marks ?? const GlushList.empty());

              final nextContext = Context(ccaller, nextMarks, ccontext.callStart, position);
              _withFrame(nextContext, (nextFrame) {
                _process(nextFrame, nextState);
              });
            });
          }
        case AcceptAction():
          _acceptedContexts.add(frame.context);
      }
    }
  }

  void _processFrame(Frame frame) {
    _withFrame(frame.copy().context, (nextFrame) {
      for (final state in frame.nextStates) {
        _process(nextFrame, state);
      }
    });
  }
}


